var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var timestamp = new Date().toISOString();
msg._syncInfo = { sync_uuid: sync_uuid, periodo: (msg.startDate||'')+'-'+(msg.endDate||''), timestamp: timestamp };
if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-IV] Sin datos.'); msg._syncInfo.empty = true; msg.payload = null; return msg;
}
// Columnas A-I: FECHA|NRO|ORIGEN|CONCEPTO|MEDIO|IMPORTE|ESTADO|UNIDAD_NEGOCIO|SYNC_UUID
var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i]; if (!r) continue;
  var importe = parseFloat(r.IMPORTE) || 0; if (importe === 0) continue;
  data.push([
    (r.FECHA || '').toString().trim(),
    (r.NRO || '').toString().trim(),
    (r.ORIGEN || '').toString().trim(),
    (r.CONCEPTO || '').toString().trim(),
    (r.MEDIO || '').toString().trim(),
    importe,
    'ok',
    (r.UNIDAD_NEGOCIO || '').toString().trim(),
    sync_uuid
  ]);
}
msg._sheetData = data; msg.payload = data;
msg._syncInfo.rowCount = data.length;
node.warn('[Sync-IV] ' + data.length + ' ingresos. UUID=' + sync_uuid);
return msg;

// El GSheet Clear sobreescribe msg.payload con la respuesta de la API
// Restaurar el array 2D desde _sheetData para que el Append funcione
if (msg._sheetData) {
  msg.payload = msg._sheetData;
}
return msg;

var info = msg._syncInfo || {};
if (info.empty) {
  node.warn('[Sync-iv] Sync omitido: sin datos');
  return msg;
}
if (msg.error) {
  node.error('[Sync-iv] ERROR: ' + msg.error);
  return msg;
}
var updatedRange = '';
if (msg.payload && msg.payload.updates) updatedRange = msg.payload.updates.updatedRange || '';
node.warn('[Sync-iv] ✅ Sync exitoso — ' + (info.rowCount || 0) + ' filas → IngresosValores');
node.warn('[Sync-iv]    UUID: ' + (info.sync_uuid || '?') + ' | Rango: ' + updatedRange);
return msg;
